package com.funkyotc.puzzleverse.nonogram.data

data class PregeneratedNonogram(
    override val id: String,
    override val difficulty: String,
    val size: Int,
    val rowClues: List<List<Int>>,
    val colClues: List<List<Int>>,
    val gridStr: String
) : com.funkyotc.puzzleverse.core.data.BrowseablePuzzle {
    override val label: String get() = id.replace("_", " ").replaceFirstChar { it.uppercase() }
    override val subtitle: String get() = "${size}x${size} • $difficulty"
    val grid: List<List<Boolean>> get() = gridStr.map { it == '1' }.chunked(size)
}

